const sender = items[0].json.sender || 'unknown-sender';
const folderName = sender.replace(/[^a-zA-Z0-9@._-]/g, '_');
return [{ json: { messageId: items[0].json.messageId, sender, folderName, attachments: items[0].json.attachments || [] } }];

const list = Object.values($input.all()).flatMap(i => i.map(x => x.json)).filter(Boolean);
const folderName = $json.folderName;
const matches = list.filter(f => f.mimeType && f.mimeType.includes('folder') && f.name === folderName);
if (matches.length === 0) return [{ json: { found: false } }];
matches.sort((a,b)=> (a.createdTime || '') > (b.createdTime || '') ? 1 : -1);
return [{ json: { found: true, folder: matches[0] } }];

const out = [];
const data = items[0].json;
if (!data.attachments || data.attachments.length === 0) return [];
for (const a of data.attachments) {
  out.push({ json: { messageId: data.messageId, sender: data.sender, folderName: data.folderName, attachment: a }, binary: { data: a.data } });
}
return out;

const files = Object.values($input.all()).flatMap(i => i.map(x => x.json)).filter(Boolean);
const candidate = $json.candidateFileName;
let exists = files.some(f => f.name === candidate && !f.trashed);
let finalName = candidate;
if (exists) {
  const ts = new Date().toISOString().replace(/[:.]/g,'-');
  const short = Math.random().toString(36).slice(2,8);
  const m = candidate.match(/^(.*?)(\.[^.]+)?$/);
  const base = m[1];
  const ext = m[2] || '';
  finalName = `${base} (copy ${ts}-${short})${ext}`;
}
return [{ json: { ...$json, uploadFileName: finalName } }];
